document.addEventListener('DOMContentLoaded', () => { initTheme(); initMobileMenu(); initStickyNavbar(); initResetButton(); trackCalculatorVisit(); }); function initTheme() { const themeToggle = document.getElementById('theme-toggle'); const storedTheme = localStorage.getItem('theme'); const systemPrefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches; const isDark = storedTheme === 'dark' || (!storedTheme && systemPrefersDark); if (isDark) { document.body.classList.add('dark-theme'); if (themeToggle) themeToggle.checked = true; } else { document.body.classList.remove('dark-theme'); if (themeToggle) themeToggle.checked = false; } if (themeToggle) { themeToggle.addEventListener('change', () => { if (themeToggle.checked) { document.body.classList.add('dark-theme'); localStorage.setItem('theme', 'dark'); } else { document.body.classList.remove('dark-theme'); localStorage.setItem('theme', 'light'); } }); } } function initStickyNavbar() { const navbar = document.getElementById('main-navbar'); if (!navbar) return; const checkScroll = () => { if (window.scrollY > 15) { navbar.classList.add('scrolled'); } else { navbar.classList.remove('scrolled'); } }; window.addEventListener('scroll', checkScroll); checkScroll(); } function initResetButton() { const resetBtn = document.getElementById('reset-btn'); const form = document.getElementById('calculator-form'); const resultsContainer = document.getElementById('calculator-results'); const alertContainer = document.getElementById('calculator-alert'); if (resetBtn && form) { resetBtn.addEventListener('click', () => { form.reset(); Utils.clearAlert(alertContainer); const outputElements = resultsContainer ? resultsContainer.querySelectorAll('[id^="result-"]') : []; outputElements.forEach(elem => { if (elem.id === 'result-bmi') { elem.innerText = '0.0'; } else if (elem.id === 'result-bmi-cat') { elem.innerText = 'Normal Weight'; } else if (elem.id === 'result-pct') { elem.innerText = '30'; } else if (elem.id === 'result-emi') { elem.innerText = '$0.00'; } else if (['result-emi-principal', 'result-emi-interest', 'result-emi-total', 'result-gst-net', 'result-gst-tax', 'result-gst-gross'].includes(elem.id)) { elem.innerText = '$0.00'; } else if (elem.id.includes('years') || elem.id.includes('months') || elem.id.includes('days') || elem.id.includes('weeks') || elem.id.includes('hours')) { elem.innerText = '0'; } else { elem.innerText = '0.00'; } }); }); } } function initMobileMenu() { const menuBtn = document.getElementById('mobile-menu-toggle'); const navLinks = document.getElementById('nav-links'); if (menuBtn && navLinks) { menuBtn.addEventListener('click', () => { const expanded = menuBtn.getAttribute('aria-expanded') === 'true'; menuBtn.setAttribute('aria-expanded', !expanded); navLinks.classList.toggle('active'); }); } } function trackCalculatorVisit() { const currentPath = window.location.pathname; if (currentPath.includes('/calculators/') && !currentPath.endsWith('/calculators/')) { const calcId = currentPath.split('/').filter(Boolean).pop(); if (!calcId) return; const calcName = document.title.split(' - ')[0] || calcId.replace(/-/g, ' '); let recent = []; try { recent = JSON.parse(localStorage.getItem('recent_calculators')) || []; } catch (e) { recent = []; } recent = recent.filter(item => item.id !== calcId); recent.unshift({ id: calcId, name: calcName, path: currentPath }); if (recent.length > 5) recent.pop(); localStorage.setItem('recent_calculators', JSON.stringify(recent)); } } export const Utils = { formatNumber(number, decimals = 2) { if (isNaN(number) || number === null || number === undefined) return ''; return new Intl.NumberFormat('en-US', { minimumFractionDigits: 0, maximumFractionDigits: decimals }).format(number); }, clearAlert(container) { if (container) container.innerHTML = ''; }, showAlert(container, type, message) { if (!container) return; const alertHTML = ` <div class="alert alert-${type} animate-fade-in" role="alert"> <span>${message}</span> </div> `; container.innerHTML = alertHTML; } };